const body = $input.first().json.body || $input.first().json;

const prompt      = body.prompt      || '';
const theme       = body.theme       || 'nature';
const style       = body.style       || 'cinematic';
const mood        = body.mood        || 'calm';
const sceneCount  = parseInt(body.sceneCount)  || 5;
const sceneLength = parseInt(body.sceneLength) || 3;
const aspectRatio = body.aspectRatio || 'portrait';

const systemPrompt = `You are an expert creative director for short-form video reels.
Generate exactly ${sceneCount} highly detailed image prompts for a ${style} ${theme} reel with a ${mood} mood.
User description: "${prompt}"

Rules:
- Each prompt describes ONE distinct scene
- Include: lighting, color palette, composition, camera angle
- Style: ${style}, Mood: ${mood}, Theme: ${theme}
- Return ONLY a valid JSON array of strings, no markdown, no explanation
- Example: ["prompt1", "prompt2"]`;

return [{ json: { systemPrompt, theme, style, mood, sceneCount, sceneLength, aspectRatio, prompt } }];

