const response = $input.first().json;
const content  = response.choices[0].message.content.trim();

let prompts;
try {
  const cleaned = content.replace(/```json|```/g, '').trim();
  prompts = JSON.parse(cleaned);
} catch(e) {
  const match = content.match(/\[.*\]/s);
  if (match) prompts = JSON.parse(match[0]);
  else throw new Error('Could not parse prompts: ' + content.slice(0, 200));
}

const prev = $('Format Request').first().json;

return prompts.map((prompt, index) => ({
  json: { prompt, sceneIndex: index, sceneCount: prev.sceneCount, sceneLength: prev.sceneLength, aspectRatio: prev.aspectRatio, style: prev.style, mood: prev.mood }
}));

