const response     = $input.first().json;
const refinedPrompt = response.choices[0].message.content.trim();
const prev          = $('Parse Prompts').first().json;

// Dimensions based on aspect ratio
const dims = {
  portrait:  { w: 576,  h: 1024 },
  landscape: { w: 1024, h: 576  },
  square:    { w: 768,  h: 768  },
};
const { w, h } = dims[prev.aspectRatio] || dims.portrait;

// Build Pollinations URL (free, no API key needed)
const encodedPrompt = encodeURIComponent(refinedPrompt);
const imageUrl = `https://image.pollinations.ai/prompt/${encodedPrompt}?width=${w}&height=${h}&nologo=true&model=flux&seed=${prev.sceneIndex}`;

return [{ json: { imageUrl, refinedPrompt, sceneIndex: prev.sceneIndex, sceneLength: prev.sceneLength } }];

// Collect all image URLs from all loop iterations
const items = $input.all();

const images     = items.map(item => item.json.imageUrl);
const sceneLength = items[0]?.json?.sceneLength || 3;

return [{
  json: {
    success: true,
    images,
    sceneLength,
    totalScenes: images.length,
    message: 'Slideshow ready!'
  }
}];
